import React, { useState } from 'react';
import '../style/Card.css'; 

const Card = ({ name, price, description }) => {
  const [quantity, setQuantity] = useState(0);

  const handleIncrement = () => {
    setQuantity(prevQuantity => prevQuantity + 1);
  };

  const handleDecrement = () => {
    if (quantity > 0) {
      setQuantity(prevQuantity => prevQuantity - 1);
    }
  };

  const handleAddToCart = () => {
    alert(`${quantity} ${name}(s) have been added to the cart!`);
  };

  const handleGoToCart = () => {
    // Logic to navigate to the cart can go here
    alert(`Navigating to cart with ${quantity} ${name}(s)!`);
  };

  return (
    <div className="card">
      {/* <img src={imgSrc} alt={name} className="cake-img" /> */}
      <div className="card-details">
        <h3 className="cake-name">{name}</h3>
        <p className="cake-description">{description}</p>
        <p className="cake-price">Price: ${price.toFixed(2)}</p>
        <div className="quantity-controls">
          <button onClick={handleDecrement} className="quantity-btn">-</button>
          <span className="quantity-display">{quantity}</span>
          <button onClick={handleIncrement} className="quantity-btn">+</button>
        </div>
        <button onClick={handleAddToCart} className="add-to-cart-btn">Add to Cart</button>
        <button onClick={handleGoToCart} className="go-to-cart-btn">Go to Cart</button>
      </div>
    </div>
  );
};

export default Card;
